/**
 * Script 4: SSR from pre-generated RSC payload benchmark
 *
 * Isolates the SSR server's work: given a pre-generated RSC payload,
 * measure only the consume + render phases (no RSC generation overhead).
 *
 * This simulates the realistic scenario where the RSC payload is already
 * available (e.g., generated by a separate RSC server or cached) and the
 * SSR server just needs to turn it into HTML.
 *
 * Phase A: createFromNodeStream(payload) → React element
 * Phase B: renderToPipeableStream(element) → HTML stream
 *
 * Measures: consume time, SSR time, TTFB, total time, HTML size, memory.
 */

import { createRequire } from 'module';
import { PassThrough } from 'stream';
import { Worker } from 'worker_threads';
import ReactDOMServer from 'react-dom/server';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { summarize } from './lib/stats.mjs';
import { printSingleTable, outputJson } from './lib/reporter.mjs';

const require = createRequire(import.meta.url);
const { renderToPipeableStream: renderToHtmlStream } = ReactDOMServer;
const __dirname = path.dirname(fileURLToPath(import.meta.url));

// Load the server bundle to set up globalThis.__webpack_require__
require('../dist/rsc/server-bundle.cjs');

// Load manifests
function loadManifest(filePath) {
  if (fs.existsSync(filePath)) {
    return JSON.parse(fs.readFileSync(filePath, 'utf8'));
  }
  return { filePathToModuleMetadata: {}, moduleLoading: { prefix: '', crossOrigin: null } };
}

const clientManifest = loadManifest(path.resolve(__dirname, '../dist/rsc/react-client-manifest.json'));
const serverManifest = loadManifest(path.resolve(__dirname, '../dist/rsc/react-server-client-manifest.json'));

const WARMUP = 10;
const ITERATIONS = parseInt(process.env.ITERATIONS || '100', 10);
const JSON_OUTPUT = process.argv.includes('--json');

/**
 * Generate RSC payload once via worker thread, save to file, return buffer.
 */
async function generateAndSavePayload() {
  const payloadPath = path.resolve(__dirname, '../dist/rsc/rsc-payload.bin');

  // Generate fresh payload via worker
  const worker = await new Promise((resolve, reject) => {
    const w = new Worker(
      path.resolve(__dirname, 'lib/rsc-worker.mjs'),
      { execArgv: ['--conditions=react-server'], env: { ...process.env, NODE_ENV: 'production' } }
    );
    w.on('message', (msg) => {
      if (msg.type === 'ready') resolve(w);
      else if (msg.type === 'error') reject(new Error(msg.error));
    });
    w.on('error', reject);
  });

  const payload = await new Promise((resolve, reject) => {
    const handler = (msg) => {
      if (msg.type === 'payload') {
        worker.off('message', handler);
        resolve(Buffer.from(msg.payload));
      } else if (msg.type === 'error') {
        worker.off('message', handler);
        reject(new Error(msg.error));
      }
    };
    worker.on('message', handler);
    worker.postMessage({ type: 'generate', id: 'save' });
  });

  worker.postMessage({ type: 'exit' });

  // Save to file
  fs.mkdirSync(path.dirname(payloadPath), { recursive: true });
  fs.writeFileSync(payloadPath, payload);
  console.log(`RSC payload saved to dist/rsc/rsc-payload.bin (${payload.length.toLocaleString()} bytes)\n`);

  return payload;
}

async function run() {
  const { buildClientRenderer } = await import('react-on-rails-rsc/client.node');
  const { createFromNodeStream } = buildClientRenderer(clientManifest, serverManifest);

  // Generate and save RSC payload (one-time, excluded from benchmark)
  const rscPayload = await generateAndSavePayload();

  console.log(`SSR from RSC payload benchmark: ${WARMUP} warmup + ${ITERATIONS} iterations\n`);

  // Warmup
  for (let i = 0; i < WARMUP; i++) {
    const ps = new PassThrough();
    ps.end(rscPayload);
    const element = await createFromNodeStream(ps);
    await new Promise((resolve, reject) => {
      const { pipe } = renderToHtmlStream(element, {
        onShellReady() {
          const pt = new PassThrough();
          pipe(pt);
          const chunks = [];
          pt.on('data', (c) => chunks.push(c));
          pt.on('end', resolve);
          pt.on('error', reject);
        },
        onError: reject,
      });
    });
  }

  if (global.gc) global.gc();

  const consumeTimes = [];
  const ssrTimes = [];
  const ttfbs = [];
  const totalTimes = [];
  const heapValues = [];
  const rssValues = [];
  let htmlSize = 0;

  for (let i = 0; i < ITERATIONS; i++) {
    const memBefore = process.memoryUsage();
    const totalStart = process.hrtime.bigint();

    // Phase A: Consume RSC payload → React element
    const consumeStart = process.hrtime.bigint();
    const ps = new PassThrough();
    ps.end(rscPayload);
    const element = await createFromNodeStream(ps);
    const consumeEnd = process.hrtime.bigint();

    // Phase B: SSR render
    const ssrStart = process.hrtime.bigint();
    const ssrResult = await new Promise((resolve, reject) => {
      let shellReadyTime = null;
      const { pipe } = renderToHtmlStream(element, {
        onShellReady() {
          shellReadyTime = Number(process.hrtime.bigint() - ssrStart);
          const pt = new PassThrough();
          pipe(pt);
          const chunks = [];
          pt.on('data', (c) => chunks.push(c));
          pt.on('end', () => resolve({ html: Buffer.concat(chunks), shellReadyTime }));
          pt.on('error', reject);
        },
        onError: reject,
      });
    });
    const ssrEnd = process.hrtime.bigint();

    const totalEnd = process.hrtime.bigint();
    const memAfter = process.memoryUsage();

    consumeTimes.push(Number(consumeEnd - consumeStart));
    ssrTimes.push(Number(ssrEnd - ssrStart));
    ttfbs.push(ssrResult.shellReadyTime);
    totalTimes.push(Number(totalEnd - totalStart));
    heapValues.push(Math.max(memAfter.heapUsed, memBefore.heapUsed));
    rssValues.push(Math.max(memAfter.rss, memBefore.rss));

    if (i === 0) {
      htmlSize = ssrResult.html.length;
    }
  }

  const results = {
    consumeTime: summarize(consumeTimes),
    ssrTime: summarize(ssrTimes),
    ttfb: summarize(ttfbs),
    totalTime: summarize(totalTimes),
    htmlSize,
    payloadSize: rscPayload.length,
    peakHeap: summarize(heapValues),
    peakRss: summarize(rssValues),
    iterations: ITERATIONS,
  };

  if (JSON_OUTPUT) {
    outputJson(results);
  } else {
    printSingleTable('SSR from RSC Payload Results', results);
  }

  return results;
}

run().catch((err) => {
  console.error('Benchmark failed:', err);
  process.exit(1);
});
